let timer = setInterval(flashText, 5000);
photoNumber = 1;

console.log(timer);

function changeColor() {
  // check if an interval has already been set up
  if (!timer) {
    timer = setInterval(flashText, 5000);
  }
}

function unhidePhoto() {
  const changer = document.getElementById(".programmingIMG2");
  changer.style.display = "flex";
}

function hidephoto() {
  const changer = document.getElementById(".programmingIMG2");
  changer.style.display = "none";
}
